changeSet.sql:
DO $$
BEGIN
    IF EXISTS (SELECT 1 FROM pg_roles WHERE rolname = 'hisaberp_app') THEN
        -- Schema: USAGE to resolve objects, CREATE so the Spring Modulith
        -- event_publication table can be created by the runtime role on a fresh DB.
        GRANT USAGE, CREATE ON SCHEMA public TO hisaberp_app;

        -- Existing objects.
        GRANT SELECT, INSERT, UPDATE, DELETE ON ALL TABLES IN SCHEMA public TO hisaberp_app;
        GRANT USAGE, SELECT, UPDATE ON ALL SEQUENCES IN SCHEMA public TO hisaberp_app;
        GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA public TO hisaberp_app;

        -- Future objects created by the admin/owner role.
        ALTER DEFAULT PRIVILEGES FOR ROLE hisaberp IN SCHEMA public
            GRANT SELECT, INSERT, UPDATE, DELETE ON TABLES TO hisaberp_app;
        ALTER DEFAULT PRIVILEGES FOR ROLE hisaberp IN SCHEMA public
            GRANT USAGE, SELECT, UPDATE ON SEQUENCES TO hisaberp_app;
        ALTER DEFAULT PRIVILEGES FOR ROLE hisaberp IN SCHEMA public
            GRANT EXECUTE ON FUNCTIONS TO hisaberp_app;
    END IF;
END
$$;
